    36→    isFinal: boolean;
    37→    [index: number]: SpeechRecognitionAlternative;
    38→}
    39→
    40→interface SpeechRecognitionAlternative {
    41→    transcript: string;
    42→}
    43→
    44→interface SpeechRecognitionErrorEvent {
    45→    error: string;
    46→}
    47→
    48→export function useVoiceInput(): UseVoiceInputReturn {
    49→    const [isRecording, setIsRecording] = useState(false);
    50→    const [isSupported, setIsSupported] = useState(false);
    51→    const [transcript, setTranscript] = useState('');
    52→    const recognitionRef = useRef<SpeechRecognition | null>(null);
    53→
    54→    useEffect(() => {
    55→        if (typeof window === 'undefined') return;
    56→
    57→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
    58→        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    59→
    60→        if (SpeechRecognition) {
    61→            // eslint-disable-next-line react-hooks/exhaustive-deps
    62→            setIsSupported(true);
    63→            const recognition = new SpeechRecognition();
    64→            recognition.continuous = true;
    65→            recognition.interimResults = true;
    66→            recognition.lang = 'fr-FR';
    67→
    68→            recognition.onresult = (event: SpeechRecognitionEvent) => {
    69→                let finalTranscript = '';
    70→
    71→                for (let i = event.resultIndex; i < event.results.length; i++) {
    72→                    const transcriptPiece = event.results[i][0].transcript;
    73→                    if (event.results[i].isFinal) {
    74→                        finalTranscript += transcriptPiece + ' ';
    75→                    }
    76→                }
    77→
    78→                if (finalTranscript) {
    79→                    setTranscript((prev) => prev + finalTranscript);
    80→                }
    81→            };
    82→
    83→            recognition.onerror = (event: SpeechRecognitionErrorEvent) => {
    84→                console.error('Speech recognition error:', event.error);
    85→                setIsRecording(false);
    86→            };
    87→
    88→            recognition.onend = () => {
    89→                setIsRecording(false);
    90→            };
    91→
    92→            recognitionRef.current = recognition;
    93→        }
    94→
    95→        return () => {
    96→            if (recognitionRef.current) {
    97→                recognitionRef.current.stop();
    98→            }
    99→        };
   100→    }, []);
   101→
   102→    const startRecording = useCallback(() => {
   103→        if (recognitionRef.current && !isRecording) {
   104→            setTranscript('');
   105→            try {
   106→                recognitionRef.current.start();
   107→                setIsRecording(true);
   108→            } catch (err) {
   109→                console.error("Failed to start recording:", err);
   110→            }
   111→        }
   112→    }, [isRecording]);
   113→
   114→    const stopRecording = useCallback(() => {
   115→        if (recognitionRef.current && isRecording) {
   116→            recognitionRef.current.stop();
   117→            setIsRecording(false);
   118→        }
   119→    }, [isRecording]);
   120→
   121→    const resetTranscript = useCallback(() => {
   122→        setTranscript('');
   123→    }, []);
   124→
   125→    return {
   126→        isRecording,
   127→        isSupported,
   128→        transcript,
   129→        startRecording,
   130→        stopRecording,
   131→        resetTranscript,
   132→    };
   133→}
