     1→/**
     2→ * K3RN.LABS — Build canonical AnalysisInput from frontend capture data
     3→ */
     4→
     5→import type { AnalysisInput, AnalysisInputFile, AnalysisInputLink } from './types';
     6→import { SCHEMA_VERSION } from './constants';
     7→
     8→interface BuildCanonicalInputParams {
     9→  text: string;
    10→  files: { name: string; type: string; size: number }[];
    11→  links: string[];
    12→  isVoice?: boolean;
    13→  lang?: string;
    14→}
    15→
    16→function mapFileType(mimeType: string): 'pdf' | 'image' | 'text' {
    17→  if (mimeType.includes('pdf')) return 'pdf';
    18→  if (mimeType.startsWith('image/')) return 'image';
    19→  return 'text';
    20→}
    21→
    22→export function buildCanonicalInput(params: BuildCanonicalInputParams): AnalysisInput {
    23→  const { text, files, links, isVoice = false, lang = 'fr' } = params;
    24→
    25→  const inputFiles: AnalysisInputFile[] = files.map((f) => ({
    26→    file_id: crypto.randomUUID(),
    27→    type: mapFileType(f.type),
    28→    size_kb: Math.round(f.size / 1024),
    29→  }));
    30→
    31→  const inputLinks: AnalysisInputLink[] = links.map((url) => ({
    32→    url,
    33→    type: 'web' as const,
    34→  }));
    35→
    36→  return {
    37→    meta: {
    38→      schema_version: SCHEMA_VERSION,
    39→      request_id: crypto.randomUUID(),
    40→      timestamp: new Date().toISOString(),
    41→      language: lang,
    42→    },
    43→    idea: {
    44→      idea_id: crypto.randomUUID(),
    45→      state: 'CAPTURED',
    46→    },
    47→    inputs: {
    48→      ...(text.trim() && {
    49→        text: {
    50→          content: text,
    51→          source: isVoice ? 'voice_transcript' as const : 'typed' as const,
    52→          length: text.length,
    53→        },
    54→      }),
    55→      ...(inputLinks.length > 0 && { links: inputLinks }),
    56→      ...(inputFiles.length > 0 && { files: inputFiles }),
    57→    },
    58→  };
    59→}
